// Extract Claude response from nested structure
const responseContent = $json.content[0].text;

// Parse JSON from Claude
let validation;
try {
  validation = JSON.parse(responseContent);
} catch(e) {
  // If Claude wrapped in markdown backticks, extract it
  const jsonMatch = responseContent.match(/```json\n?(.*?)\n?```/s);
  if (jsonMatch) {
    validation = JSON.parse(jsonMatch[1]);
  } else if (responseContent.match(/^\{/)) {
    // Try raw object
    validation = JSON.parse(responseContent);
  } else {
    throw new Error('Invalid JSON from Claude: ' + responseContent.substring(0, 200));
  }
}

// Validate required top-level fields
const requiredFields = [
  'niche_name',
  'geography',
  'market_size_estimate',
  'competitors',
  'pain_points',
  'monetization_angles',
  'viability_score',
  'score_reasoning',
  'recommended_icp',
  'recommended_offer_angle',
  'key_opportunities',
  'key_risks'
];

for (const field of requiredFields) {
  if (validation[field] === undefined || validation[field] === null) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate market_size_estimate object
if (!validation.market_size_estimate.tam_annual || !validation.market_size_estimate.reasoning) {
  throw new Error('market_size_estimate missing tam_annual or reasoning');
}

// Validate competitors array
if (!Array.isArray(validation.competitors) || validation.competitors.length !== 5) {
  throw new Error(`Expected exactly 5 competitors, got ${validation.competitors.length}`);
}

for (let i = 0; i < validation.competitors.length; i++) {
  const competitor = validation.competitors[i];
  if (!competitor.name || !competitor.focus || !competitor.market_share_est) {
    throw new Error(`Competitor ${i + 1} missing name, focus, or market_share_est`);
  }
}

// Validate pain_points array
if (!Array.isArray(validation.pain_points) || validation.pain_points.length < 5) {
  throw new Error(`Expected minimum 5 pain points, got ${validation.pain_points.length}`);
}

for (let i = 0; i < validation.pain_points.length; i++) {
  if (!validation.pain_points[i] || validation.pain_points[i].trim().length === 0) {
    throw new Error(`Pain point ${i + 1} is empty`);
  }
}

// Validate monetization_angles array
if (!Array.isArray(validation.monetization_angles) || validation.monetization_angles.length < 3) {
  throw new Error(`Expected minimum 3 monetization angles, got ${validation.monetization_angles.length}`);
}

for (let i = 0; i < validation.monetization_angles.length; i++) {
  const angle = validation.monetization_angles[i];
  if (!angle.angle || !angle.revenue_model || !angle.price_target) {
    throw new Error(`Monetization angle ${i + 1} missing angle, revenue_model, or price_target`);
  }
}

// Validate viability_score
if (typeof validation.viability_score !== 'number' || validation.viability_score < 0 || validation.viability_score > 100) {
  throw new Error(`viability_score must be number 0-100, got: ${validation.viability_score}`);
}

// Validate score_reasoning
if (!validation.score_reasoning || validation.score_reasoning.trim().length === 0) {
  throw new Error('score_reasoning cannot be empty');
}

// Validate recommended_icp object
if (!validation.recommended_icp.profile || !validation.recommended_icp.pain_priority) {
  throw new Error('recommended_icp missing profile or pain_priority');
}

// Validate recommended_offer_angle
if (!validation.recommended_offer_angle || validation.recommended_offer_angle.trim().length === 0) {
  throw new Error('recommended_offer_angle cannot be empty');
}

// Validate key_opportunities array
if (!Array.isArray(validation.key_opportunities) || validation.key_opportunities.length < 3) {
  throw new Error(`Expected minimum 3 key opportunities, got ${validation.key_opportunities.length}`);
}

for (let i = 0; i < validation.key_opportunities.length; i++) {
  if (!validation.key_opportunities[i] || validation.key_opportunities[i].trim().length === 0) {
    throw new Error(`Key opportunity ${i + 1} is empty`);
  }
}

// Validate key_risks array
if (!Array.isArray(validation.key_risks) || validation.key_risks.length < 2) {
  throw new Error(`Expected minimum 2 key risks, got ${validation.key_risks.length}`);
}

for (let i = 0; i < validation.key_risks.length; i++) {
  if (!validation.key_risks[i] || validation.key_risks[i].trim().length === 0) {
    throw new Error(`Key risk ${i + 1} is empty`);
  }
}

// Add viability category
let viability_category;
if (validation.viability_score >= 80) {
  viability_category = 'green_light';
} else if (validation.viability_score >= 60) {
  viability_category = 'yellow_flag';
} else {
  viability_category = 'red_flag';
}

validation.viability_category = viability_category;

return validation;
